class Solution {
    public int longestSemiRepetitiveSubstring(String s) {
        int maxLen = 1;
        int lastSeen = -1;
        int pairIndex = -1;

        for (int i = 1; i < s.length(); i++) {
            if (s.charAt(i) == s.charAt(i - 1)) {
                if (pairIndex != -1 && s.charAt(i) != s.charAt(pairIndex)) {
                    lastSeen = pairIndex;
                }
                pairIndex = i - 1;
            }
            maxLen = Math.max(maxLen, i - lastSeen);
        }
        return maxLen;
    }
}
